const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const COMPONENT_TYPES = ["rune", "moonstone"];

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function basePremiumFor(item: ItemSpec): number {
  return BASE_PREMIUMS[item.type] ?? 0;
}

function sumBasePremiums(items: ItemSpec[]): number {
  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
}

function blockAdjustment(items: ItemSpec[]): number {
  let adjustment = 0;
  for (const componentType of COMPONENT_TYPES) {
    const count = items.filter((item) => item.type === componentType).length;
    if (count === BLOCK_SIZE) {
      adjustment += BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
    }
  }
  return adjustment;
}

